function getPuzzlesByTag(tag) {
  var arr = BEGINNER_PUZZLES_BY_TAG[tag] || []
  var copy = arr.slice()
  for (var i = copy.length - 1; i > 0; i--) {
    var j = Math.floor(Math.random() * (i + 1))
    var tmp = copy[i]; copy[i] = copy[j]; copy[j] = tmp
  }
  return copy
}

module.exports = { getPuzzlesByTag: getPuzzlesByTag, BEGINNER_PUZZLES_BY_TAG: BEGINNER_PUZZLES_BY_TAG }
